import React, { useState, useCallback } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { contactAPI } from '../services/api';
import toast from 'react-hot-toast';
import { useDropzone } from 'react-dropzone';
import { Plus, Upload, Search, Trash2, UserPlus, List, X } from 'lucide-react';

const inputStyle = { width: '100%', padding: '10px 12px', border: '1px solid #e2e8f0', borderRadius: '8px', fontSize: '14px', outline: 'none', boxSizing: 'border-box' };

export default function ContactsPage() {
  const qc = useQueryClient();
  const queryClient = qc;
  const [activeList, setActiveList] = useState(null);
  const [search, setSearch] = useState('');
  const [showAddContact, setShowAddContact] = useState(false);
  const [showCreateList, setShowCreateList] = useState(false);
  const [showImport, setShowImport] = useState(false);
  const [importJobId, setImportJobId] = useState(null);
  const [contactForm, setContactForm] = useState({ phone: '', first_name: '', last_name: '', email: '' });
  const [listForm, setListForm] = useState({ name: '', description: '' });

  const { data: lists = [] } = useQuery({ queryKey: ['lists'], queryFn: () => contactAPI.getLists().then(r => r.data.data) });
  const { data: contactsData } = useQuery({
    queryKey: ['contacts', activeList, search],
    queryFn: () => contactAPI.getContacts({ list_id: activeList, search, limit: 100 }).then(r => r.data),
  });
  const contacts = contactsData?.data || [];
  const total = contactsData?.pagination?.total || 0;

  const { data: importStatus } = useQuery({
    queryKey: ['import', importJobId],
    queryFn: () => contactAPI.getImportStatus(importJobId).then(r => r.data.data),
    enabled: !!importJobId,
    refetchInterval: (data) => (data?.status === 'processing' || data?.status === 'pending') ? 2000 : false,
    onSuccess: (data) => {
      if (data?.status === 'completed') {
        qc.invalidateQueries(['contacts']);
        qc.invalidateQueries(['lists']);
      }
    },
  });

  const createListMutation = useMutation({
    mutationFn: (data) => contactAPI.createList(data),
    onSuccess: () => { qc.invalidateQueries(['lists']); setShowCreateList(false); setListForm({ name: '', description: '' }); toast.success('List created!'); },
  });

  const addContactMutation = useMutation({
    mutationFn: (data) => contactAPI.createContact({ ...data, list_ids: activeList ? [activeList] : [] }),
    onSuccess: () => { qc.invalidateQueries(['contacts']); qc.invalidateQueries(['lists']); setShowAddContact(false); setContactForm({ phone: '', first_name: '', last_name: '', email: '' }); toast.success('Contact added!'); },
    onError: (e) => toast.error(e.response?.data?.message || 'Failed'),
  });

  const deleteContactMutation = useMutation({
    mutationFn: (id) => contactAPI.deleteContact(id),
    onSuccess: () => { qc.invalidateQueries(['contacts']); toast.success('Deleted'); },
  });

  const onDrop = useCallback(async (acceptedFiles) => {
    const file = acceptedFiles[0];
    if (!file) return;
    const formData = new FormData();
    formData.append('file', file);
    if (activeList) formData.append('list_id', activeList);
    try {
      const res = await contactAPI.importContacts(formData);
      setImportJobId(res.data.data.import_id);
      toast.success('Import started!');
    } catch (e) {
      toast.error(e.response?.data?.message || 'Import failed');
    }
  }, [activeList]);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({ onDrop, accept: { 'text/csv': ['.csv'], 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet': ['.xlsx'] } });

  return (
    <div style={{ padding: '32px', background: '#f8fafc', minHeight: '100vh' }}>
      <div style={{ display: 'flex', gap: '24px', height: 'calc(100vh - 100px)' }}>
        {/* Sidebar - Lists */}
        <div style={{ width: '240px', flexShrink: 0 }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
            <h2 style={{ fontSize: '16px', fontWeight: 700, color: '#0f172a' }}>Lists</h2>
            <button onClick={() => setShowCreateList(true)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#6366f1' }}>
              <Plus size={18} />
            </button>
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
            <button
              onClick={() => setActiveList(null)}
              style={{
                display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                padding: '10px 12px', borderRadius: '8px', border: 'none', cursor: 'pointer',
                background: !activeList ? '#eef2ff' : 'white', color: !activeList ? '#6366f1' : '#374151',
                fontWeight: !activeList ? 600 : 400, fontSize: '14px', textAlign: 'left'
              }}>
              <span style={{ display: 'flex', alignItems: 'center', gap: '8px' }}><List size={14} />All Contacts</span>
              <span style={{ fontSize: '12px', background: '#f1f5f9', padding: '2px 6px', borderRadius: '10px', color: '#64748b' }}>{total}</span>
            </button>
            {lists.map(list => (
              <div key={list.id} style={{ position: 'relative' }}>
                <button
                  onClick={() => setActiveList(list.id)}
                  style={{
                    display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                    padding: '10px 12px', borderRadius: '8px', border: 'none', cursor: 'pointer', width: '100%',
                    background: activeList === list.id ? '#eef2ff' : 'white', color: activeList === list.id ? '#6366f1' : '#374151',
                    fontWeight: activeList === list.id ? 600 : 400, fontSize: '14px', textAlign: 'left'
                  }}>
                  <span>{list.name}</span>
                  <span style={{ fontSize: '12px', background: '#f1f5f9', padding: '2px 6px', borderRadius: '10px', color: '#64748b' }}>
                    {list.actual_count || 0}
                  </span>
                </button>
              </div>
            ))}
          </div>
        </div>

        {/* Main */}
        <div style={{ flex: 1 }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
            <h1 style={{ fontSize: '22px', fontWeight: 700, color: '#0f172a' }}>
              {activeList ? lists.find(l => l.id === activeList)?.name : 'All Contacts'}
              <span style={{ fontSize: '14px', color: '#94a3b8', fontWeight: 400, marginLeft: '8px' }}>{total} contacts</span>
            </h1>
            <div style={{ display: 'flex', gap: '10px' }}>
              <button onClick={() => setShowImport(!showImport)} style={{
                display: 'flex', alignItems: 'center', gap: '6px', padding: '9px 16px',
                background: 'white', border: '1px solid #e2e8f0', borderRadius: '8px', cursor: 'pointer', fontSize: '13px', fontWeight: 500
              }}><Upload size={14} /> Import</button>
              <button onClick={() => setShowAddContact(true)} style={{
                display: 'flex', alignItems: 'center', gap: '6px', padding: '9px 16px',
                background: 'linear-gradient(135deg, #6366f1, #8b5cf6)', border: 'none',
                borderRadius: '8px', color: 'white', cursor: 'pointer', fontSize: '13px', fontWeight: 600
              }}><UserPlus size={14} /> Add Contact</button>
            </div>
          </div>

          {/* Search */}
          <div style={{ position: 'relative', marginBottom: '16px' }}>
            <Search size={16} style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)', color: '#94a3b8' }} />
            <input placeholder="Search by phone, name, or email..." value={search}
              onChange={e => setSearch(e.target.value)}
              style={{ ...inputStyle, paddingLeft: '36px', boxShadow: '0 1px 3px rgba(0,0,0,0.05)' }} />
          </div>

          {/* Import Zone */}
          {showImport && (
            <div style={{ marginBottom: '16px' }}>
              <div {...getRootProps()} style={{
                border: `2px dashed ${isDragActive ? '#6366f1' : '#e2e8f0'}`,
                borderRadius: '12px', padding: '32px', textAlign: 'center', cursor: 'pointer',
                background: isDragActive ? '#eef2ff' : 'white', transition: 'all 0.2s'
              }}>
                <input {...getInputProps()} />
                <Upload size={32} style={{ color: '#6366f1', margin: '0 auto 12px' }} />
                <p style={{ color: '#374151', fontWeight: 500 }}>Drop CSV/Excel file here or click to select</p>
                <p style={{ color: '#94a3b8', fontSize: '13px', marginTop: '6px' }}>Required column: phone. Optional: first_name, last_name, email</p>
              </div>
              {importStatus && (
                <div style={{ marginTop: '12px', padding: '12px 16px', background: 'white', borderRadius: '8px', border: '1px solid #e2e8f0' }}>
                  <div style={{ display: 'flex', gap: '16px', fontSize: '13px' }}>
                    <span>Status: <strong>{importStatus.status}</strong></span>
                    <span style={{ color: '#22c55e' }}>Imported: {importStatus.imported}</span>
                    <span style={{ color: '#ef4444' }}>Failed: {importStatus.failed}</span>
                    <span style={{ color: '#f59e0b' }}>Duplicates: {importStatus.duplicates}</span>
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Contacts Table */}
          <div style={{ background: 'white', borderRadius: '12px', border: '1px solid #f1f5f9', overflow: 'hidden' }}>
            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
              <thead>
                <tr style={{ borderBottom: '1px solid #f1f5f9' }}>
                  {['Phone', 'Name', 'Email', 'Status', 'Actions'].map(h => (
                    <th key={h} style={{ padding: '10px 14px', textAlign: 'left', fontSize: '12px', fontWeight: 600, color: '#94a3b8' }}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {contacts.length === 0 ? (
                  <tr><td colSpan={5} style={{ padding: '40px', textAlign: 'center', color: '#94a3b8' }}>No contacts found</td></tr>
                ) : contacts.map(c => (
                  <tr key={c.id} style={{ borderBottom: '1px solid #f8fafc' }}>
                    <td style={{ padding: '12px 14px', fontSize: '14px', fontWeight: 500, fontFamily: 'monospace', color: '#0f172a' }}>{c.phone}</td>
                    <td style={{ padding: '12px 14px', fontSize: '14px', color: '#374151' }}>{[c.first_name, c.last_name].filter(Boolean).join(' ') || '—'}</td>
                    <td style={{ padding: '12px 14px', fontSize: '13px', color: '#64748b' }}>{c.email || '—'}</td>
                    <td style={{ padding: '12px 14px' }}>
                      <span style={{
                        padding: '2px 8px', borderRadius: '10px', fontSize: '11px', fontWeight: 600,
                        background: c.is_opted_out ? '#fee2e2' : '#dcfce7',
                        color: c.is_opted_out ? '#dc2626' : '#16a34a'
                      }}>{c.is_opted_out ? 'Opted Out' : 'Active'}</span>
                    </td>
                    <td style={{ padding: '12px 14px' }}>
                      <button onClick={() => { if (window.confirm('Delete contact?')) deleteContactMutation.mutate(c.id); }}
                        style={{ padding: '5px', background: 'none', border: 'none', cursor: 'pointer', color: '#ef4444' }}>
                        <Trash2 size={14} />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {/* Add Contact Modal */}
      {showAddContact && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000 }}>
          <div style={{ background: 'white', borderRadius: '16px', padding: '28px', width: '440px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
              <h3 style={{ fontSize: '18px', fontWeight: 700 }}>Add Contact</h3>
              <button onClick={() => setShowAddContact(false)} style={{ background: 'none', border: 'none', cursor: 'pointer' }}><X size={18} /></button>
            </div>
            <form onSubmit={e => { e.preventDefault(); addContactMutation.mutate(contactForm); }}>
              <div style={{ display: 'grid', gap: '14px' }}>
                <div>
                  <label style={{ fontSize: '13px', fontWeight: 500, display: 'block', marginBottom: '5px' }}>Phone * (e.g. +12125551234)</label>
                  <input style={inputStyle} placeholder="+12125551234" value={contactForm.phone}
                    onChange={e => setContactForm({ ...contactForm, phone: e.target.value })} required />
                </div>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                  <div>
                    <label style={{ fontSize: '13px', fontWeight: 500, display: 'block', marginBottom: '5px' }}>First Name</label>
                    <input style={inputStyle} value={contactForm.first_name} onChange={e => setContactForm({ ...contactForm, first_name: e.target.value })} />
                  </div>
                  <div>
                    <label style={{ fontSize: '13px', fontWeight: 500, display: 'block', marginBottom: '5px' }}>Last Name</label>
                    <input style={inputStyle} value={contactForm.last_name} onChange={e => setContactForm({ ...contactForm, last_name: e.target.value })} />
                  </div>
                </div>
                <div>
                  <label style={{ fontSize: '13px', fontWeight: 500, display: 'block', marginBottom: '5px' }}>Email</label>
                  <input type="email" style={inputStyle} value={contactForm.email} onChange={e => setContactForm({ ...contactForm, email: e.target.value })} />
                </div>
              </div>
              <div style={{ display: 'flex', gap: '10px', marginTop: '20px', justifyContent: 'flex-end' }}>
                <button type="button" onClick={() => setShowAddContact(false)} style={{ padding: '9px 18px', border: '1px solid #e2e8f0', borderRadius: '8px', background: 'white', cursor: 'pointer' }}>Cancel</button>
                <button type="submit" style={{ padding: '9px 20px', background: '#6366f1', border: 'none', borderRadius: '8px', color: 'white', fontWeight: 600, cursor: 'pointer' }}>
                  {addContactMutation.isPending ? 'Adding...' : 'Add Contact'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Create List Modal */}
      {showCreateList && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000 }}>
          <div style={{ background: 'white', borderRadius: '16px', padding: '28px', width: '400px' }}>
            <h3 style={{ fontSize: '18px', fontWeight: 700, marginBottom: '20px' }}>Create List</h3>
            <form onSubmit={e => { e.preventDefault(); createListMutation.mutate(listForm); }}>
              <div style={{ display: 'grid', gap: '14px' }}>
                <div>
                  <label style={{ fontSize: '13px', fontWeight: 500, display: 'block', marginBottom: '5px' }}>List Name *</label>
                  <input style={inputStyle} value={listForm.name} onChange={e => setListForm({ ...listForm, name: e.target.value })} required />
                </div>
                <div>
                  <label style={{ fontSize: '13px', fontWeight: 500, display: 'block', marginBottom: '5px' }}>Description</label>
                  <textarea style={{ ...inputStyle, minHeight: '80px' }} value={listForm.description} onChange={e => setListForm({ ...listForm, description: e.target.value })} />
                </div>
              </div>
              <div style={{ display: 'flex', gap: '10px', marginTop: '20px', justifyContent: 'flex-end' }}>
                <button type="button" onClick={() => setShowCreateList(false)} style={{ padding: '9px 18px', border: '1px solid #e2e8f0', borderRadius: '8px', background: 'white', cursor: 'pointer' }}>Cancel</button>
                <button type="submit" style={{ padding: '9px 20px', background: '#6366f1', border: 'none', borderRadius: '8px', color: 'white', fontWeight: 600, cursor: 'pointer' }}>Create</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
